from flask import Flask, request, jsonify, session
from werkzeug.security import generate_password_hash, check_password_hash
import pyotp
import os

app = Flask(__name__)
app.secret_key = os.urandom(24)

# In-memory user storage for demonstration purposes
users = {
    "user@example.com": {
        "password": generate_password_hash("securepassword"),
        "mfa_enabled": True,
        "mfa_secret": pyotp.random_base32()
    }
}

@app.route('/api/login', methods=['POST'])
def login():
    data = request.json
    email = data.get('email')
    password = data.get('password')

    user = users.get(email)
    if user and check_password_hash(user['password'], password):
        if user['mfa_enabled']:
            session['email'] = email
            return jsonify({"message": "MFA required", "mfa_enabled": True}), 200
        else:
            session['email'] = email
            return jsonify({"message": "Access granted"}), 200
    return jsonify({"message": "Invalid credentials"}), 401

@app.route('/api/verify-mfa', methods=['POST'])
def verify_mfa():
    data = request.json
    otp = data.get('otp')

    user = users.get(session.get('email'))
    if user and pyotp.TOTP(user['mfa_secret']).verify(otp):
        return jsonify({"message": "Access granted"}), 200
    return jsonify({"message": "Invalid OTP"}), 401

@app.route('/api/direct-login', methods=['POST'])
def direct_login():
    data = request.json
    email = data.get('email')
    api_key = data.get('api_key')

    # Replace with your actual API key validation
    if api_key == "your_secure_api_key":
        user = users.get(email)
        if user:
            session['email'] = email
            return jsonify({"message": "Access granted"}), 200
    return jsonify({"message": "Unauthorized"}), 401

if __name__ == '__main__':
    app.run(debug=True)